class ImageProcessingController < ApplicationController
  require 'securerandom'
  require 'shellwords'

  def process_image
    uploaded_file = params[:image]
    target_format = params[:format]
    target_size = params[:size]

    unless uploaded_file && target_format && target_size
      render plain: "Missing parameters", status: :unprocessable_entity and return
    end

    input_extension = File.extname(uploaded_file.original_filename)
    input_filename = "#{SecureRandom.hex}#{input_extension}"
    output_filename = "#{SecureRandom.hex}.#{target_format}"

    input_path  = Rails.root.join("tmp", input_filename)
    output_path = Rails.root.join("tmp", output_filename)

    File.open(input_path, 'wb') do |file|
      file.write(uploaded_file.read)
    end

    command = "convert #{Shellwords.escape(input_path.to_s)} -resize #{Shellwords.escape(target_size.to_s)} #{Shellwords.escape(output_path.to_s)}"
    if system(command) && File.exist?(output_path)
      send_file output_path, disposition: 'attachment', filename: output_filename
    else
      render plain: "Image conversion failed", status: :internal_server_error
    end
  ensure
    File.delete(input_path)  if defined?(input_path) && File.exist?(input_path)
    File.delete(output_path) if defined?(output_path) && File.exist?(output_path)
  end
end